+
+    Label small_copy, forward_main, backward_main, loop_fwd, loop_bwd,
+          tail_fwd, tail_bwd, done;
@@ -900,2 +908,7 @@
-    __ bind(loop_forward);
-    __ vsetvli(vl, cnt, sew, Assembler::m8);
+    /* small copy path (≤ 32 bytes) */
+    const int max_elems_small = 32 / granularity;
+    if (max_elems_small > 0) {
+      __ li(tmp0, max_elems_small);
+      __ bleu(cnt, tmp0, small_copy);
+    }
+
@@ -903,1 +916,3 @@
