-    __ sub(cnt, cnt, vl);
-    if (sew != Assembler::e8) {
-      // when sew == e8 (e.g., elem size is 1 byte), slli R, R, 0 is a nop and unnecessary
-      __ slli(vl, vl, sew);
+    /* small copy */
+    if (max_elems_small > 0) {
+      __ bind(small_copy);
+      __ vsetvli(tmp0, cnt, sew, Assembler::m8);
+      __ vlex_v(v0, src, sew);
+      __ vsex_v(v0, dst, sew);
+      __ j(done);
@@ -912,1 +929,0 @@
