+    /* forward copy path */
+    __ bind(forward_main);
+    __ vsetvli(saved_vl, cnt, sew, Assembler::m8);
@@ -918,1 +934,25 @@
-    if (is_backward) {
+    if (granularity > 1) {
+      __ slli(bytes_per_iter, saved_vl, exact_log2(granularity));
+    } else {
+      __ mv(bytes_per_iter, saved_vl);
+    }
+
+    /* forward copy */
+    __ bind(loop_fwd);
+    {
+      __ blt(cnt, saved_vl, tail_fwd);
+      __ vlex_v(v0, src, sew);
+      __ vsex_v(v0, dst, sew);
+      __ add(src, src, bytes_per_iter);
+      __ add(dst, dst, bytes_per_iter);
+      __ sub(cnt, cnt, saved_vl);
+      __ bnez(cnt, loop_fwd);
+    }
+
+    /* forward tail */
+    __ bind(tail_fwd);
+    {
+      __ beqz(cnt, done);
+      __ vsetvli(tmp0, cnt, sew, Assembler::m8);
+      __ vlex_v(v0, src, sew);
+      __ vsex_v(v0, dst, sew);
@@ -920,0 +960,4 @@
+    }
+
+    /* backward copy path */
+    __ bind(backward_main);
@@ -921,5 +965,36 @@
-      __ bind(loop_backward);
-      __ sub(t0, cnt, vl);
-      if (sew != Assembler::e8) {
-        // when sew == e8 (e.g., elem size is 1 byte), slli R, R, 0 is a nop and unnecessary
-        __ slli(t0, t0, sew);
+    if (granularity > 1) {
+      __ slli(tmp0, count, exact_log2(granularity));
+    } else {
+      __ mv(tmp0, count);
+    }
+    __ add(src, src, tmp0);
+    __ add(dst, dst, tmp0);
+
+    __ vsetvli(saved_vl, cnt, sew, Assembler::m8);
+
+    if (granularity > 1) {
+      __ slli(bytes_per_iter, saved_vl, exact_log2(granularity));
+    } else {
+      __ mv(bytes_per_iter, saved_vl);
+    }
+
+    /* backward copy */
+    __ bind(loop_bwd);
+    {
+      __ blt(cnt, saved_vl, tail_bwd);
+      __ vlex_v(v0, src, sew);
+      __ vsex_v(v0, dst, sew);
+      __ sub(src, src, bytes_per_iter);
+      __ sub(dst, dst, bytes_per_iter);
+      __ sub(cnt, cnt, saved_vl);
+      __ bnez(cnt, loop_bwd);
+    }
+
+    /* backward tail */
+    __ bind(tail_bwd);
+    {
+      __ beqz(cnt, done);
+      if (granularity > 1) {
+        __ slli(bytes_per_iter, cnt, exact_log2(granularity));
+      } else {
+        __ mv(bytes_per_iter, cnt);
@@ -927,7 +1002,6 @@
