+
+      __ vsetvli(tmp0, cnt, sew, Assembler::m8);
+      __ sub(src, src, bytes_per_iter);
+      __ sub(dst, dst, bytes_per_iter);
+      __ vlex_v(v0, src, sew);
+      __ vsex_v(v0, dst, sew);
